// Parse the Claude response and extract the JSON deal object
const content = items[0].json.content || [];
const textBlock = content.find(b => b.type === 'text');
if (!textBlock) throw new Error('No text block in intake response');

let raw = textBlock.text.trim();
raw = raw.replace(/^```json\s*/,'').replace(/```\s*$/,'').trim();

const deal = JSON.parse(raw);
console.log('Intake extracted:', JSON.stringify(deal, null, 2));

return [{ json: deal }];

